using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    // Build the graph
    vector<vector<long long>> graph(c + 1);
    for (auto& conn : connections) {
        long long u = conn[0], v = conn[1];
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    // DSU (Disjoint Set Union) to find connected components
    vector<long long> parent(c + 1);
    vector<long long> rank(c + 1);
    vector<bool> is_online(c + 1, true);

    // Initialize DSU
    for (long long i = 1; i <= c; ++i) {
        parent[i] = i;
        rank[i] = 1;
    }

    // Find function with path compression
    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // Union function
    void union_sets(long long x, long long y) {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x != root_y) {
            if (rank[root_x] < rank[root_y]) {
                parent[root_x] = root_y;
            } else {
                parent[root_y] = root_x;
                if (rank[root_x] == rank[root_y]) {
                    rank[root_x]++;
                }
            }
        }
    }

    // Build the DSU structure based on connections
    for (auto& conn : connections) {
        long long u = conn[0], v = conn[1];
        union_sets(u, v);
    }

    vector<long long> result;

    // Process queries
    for (auto& query : queries) {
        long long type = query[0], x = query[1];
        if (type == 1) {
            if (is_online[x]) {
                result.push_back(x);
            } else {
                // Find the root of x
                long long root_x = find(x);
                // Find the minimum online node in the same component
                long long min_online = -1;
                for (long long i = 1; i <= c; ++i) {
                    if (is_online[i] && find(i) == root_x) {
                        if (min_online == -1 || i < min_online) {
                            min_online = i;
                        }
                    }
                }
                result.push_back(min_online);
            }
        } else {
            // Mark x as offline
            is_online[x] = false;
        }
    }

    return result;
}

